function r(t){return new Intl.NumberFormat("zh-CN").format(t)}function o(t){if(t.total_tokens!=null)return t.total_tokens;if(t.prompt_tokens!=null&&t.completion_tokens!=null)return t.prompt_tokens+t.completion_tokens}function u(t){return t<=0?"0s":`${(t/1e3).toFixed(1)}s`}function s(t,n){return n<=0?"0%":`${Math.round(t/n*100)}%`}function i(t){if(!t)return"-";const n=new Date(t);if(Number.isNaN(n.getTime()))return t;const e=a=>String(a).padStart(2,"0");return`${n.getFullYear()}-${e(n.getMonth()+1)}-${e(n.getDate())} ${e(n.getHours())}:${e(n.getMinutes())}:${e(n.getSeconds())}`}function l(t){return t<500?"stats-latency-good":t<2e3?"stats-latency-warn":"stats-latency-bad"}export{i as a,r as b,s as c,o as d,u as f,l};
